import{_ as t,o as s,c as a,a7 as i}from"./chunks/framework.C5fSpjcB.js";const h=JSON.parse('{"title":"Base Building System","description":"","frontmatter":{},"headers":[],"relativePath":"en/systems/base.md","filePath":"en/systems/base.md","lastUpdated":1775394001000}'),r={name:"en/systems/base.md"};function n(o,e,l,d,c,u){return s(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="base-building-system" tabindex="-1">Base Building System <a class="header-anchor" href="#base-building-system" aria-label="Permalink to &quot;Base Building System&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The base serves as the player&#39;s headquarters, where various facilities can be constructed to generate resources and enhance characters.</p><h2 id="key-facilities" tabindex="-1">Key Facilities <a class="header-anchor" href="#key-facilities" aria-label="Permalink to &quot;Key Facilities&quot;">​</a></h2><p>The base in Morimens is centered around <strong>Mythag University</strong> (弥萨格大学), located in the Kingdom of Leo. Rather than a traditional building system, the base provides access to various functional facilities that support daily progression.</p><table tabindex="0"><thead><tr><th>Facility</th><th>Function</th><th>Details</th></tr></thead><tbody><tr><td><strong>Smelting Room</strong> (冶炼室)</td><td>Equipment/item exchange</td><td>Exchange and craft items, gear, and materials</td></tr><tr><td><strong>Assignments</strong> (外勤代理)</td><td>Auto-dispatch system</td><td>Send Awakeners on assignments that reward Rose Scrip, Erosion Pearls, and various materials daily</td></tr><tr><td><strong>Curriculum</strong> (课程)</td><td>Advanced training</td><td>Complete courses to earn Mimetic Crystals, Thousand-Face Seals, and Rose Scrip</td></tr><tr><td><strong>Daily Training</strong> (每日训练)</td><td>Daily tasks</td><td>Merged daily + weekly tasks; can use proxy vouchers for quick completion (up to 5 times). Grants 500 EXP/day</td></tr><tr><td><strong>Weekly Trial</strong> (每周试炼)</td><td>Weekly challenges</td><td>Weekly challenge missions awarding 100/150/250 Silver and Erosion Pearls</td></tr><tr><td><strong>Alchemy</strong> (炼金)</td><td>Material synthesis</td><td>Combine 3 lower-tier materials into 1 higher-tier material; 30 Mimetic Crystals = 1 advanced skill material</td></tr></tbody></table><h2 id="assignments-outfield-agent" tabindex="-1">Assignments (Outfield Agent) <a class="header-anchor" href="#assignments-outfield-agent" aria-label="Permalink to &quot;Assignments (Outfield Agent)&quot;">​</a></h2><p>The Assignments system allows you to dispatch Awakeners on automated missions. Rewards are settled daily and include:</p><ul><li><strong>Rose Scrip</strong> (蔷薇金券) -- The primary universal currency</li><li><strong>Erosion Pearls</strong> (融蚀之珠) -- Used in the Deep Dive shop</li><li><strong>Various materials</strong> -- Ascension caskets, skill supplies, and more</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The &quot;Recipe Compendium&quot; assignment type grants 4,000 base Rose Scrip plus an additional 2,000 for every 20 levels of difficulty difference. Prioritize these for maximum currency income.</p></div><h2 id="curriculum" tabindex="-1">Curriculum <a class="header-anchor" href="#curriculum" aria-label="Permalink to &quot;Curriculum&quot;">​</a></h2><p>The Curriculum system offers advanced courses that provide core progression materials:</p><ul><li><strong>Mimetic Crystals</strong> (拟态凝晶) -- Universal synthesis resource (30 = 1 advanced skill material)</li><li><strong>Thousand-Face Seals</strong> (千面印章) -- Covenant enhancement and transcription material</li><li><strong>Rose Scrip</strong> -- Additional currency income</li></ul><h2 id="resource-tips" tabindex="-1">Resource Tips <a class="header-anchor" href="#resource-tips" aria-label="Permalink to &quot;Resource Tips&quot;">​</a></h2><ol><li><strong>Check Assignments daily</strong> -- Rewards settle automatically each day; reassign Awakeners to maximize output</li><li><strong>Complete Daily Training</strong> -- Use proxy vouchers to save time if available</li><li><strong>Run Curriculum regularly</strong> -- Mimetic Crystals are essential for late-game material synthesis</li><li><strong>Visit the Smelting Room</strong> -- New recipes unlock as you progress through the main story</li></ol>',15)])])}const g=t(r,[["render",n]]);export{h as __pageData,g as default};
